    23→func printPlanSummary(b []byte) {
    24→    var parsed struct{
    25→        PlanID string `json:"plan_id"`
    26→        Options []map[string]any `json:"options"`
    27→    }
    28→    if err := jsonUnmarshal(b, &parsed); err == nil && parsed.PlanID != "" && len(parsed.Options) > 0 {
    29→        fmt.Printf("Planner produced plan (id=%s) with %d option(s):\n", parsed.PlanID, len(parsed.Options))
    30→        for i, o := range parsed.Options {
    31→            id, _ := o["id"].(string)
    32→            typ, _ := o["type"].(string)
    33→            fmt.Printf("  %d) %s (%s)\n", i+1, id, typ)
    34→        }
    35→    } else {
    36→        fmt.Printf("Planner finished but plan.json validation failed or missing keys: %v\n", err)
    37→    }
    38→}
    39→
    40→func printNextSummary(b []byte) {
    41→    var parsed struct{
    42→        Action string `json:"action"`
    43→        Notes  string `json:"notes"`
    44→    }
    45→    if err := jsonUnmarshal(b, &parsed); err == nil && parsed.Action != "" {
    46→        fmt.Printf("Reducer next action: %s", parsed.Action)
    47→        if parsed.Notes != "" { fmt.Printf(" (%s)", parsed.Notes) }
    48→        fmt.Println()
    49→    } else {
    50→        fmt.Printf("Reducer output invalid or missing keys: %v\n", err)
    51→    }
    52→}
