    54→// TransflowCmd provides the CLI entrypoint to run transflows
    55→func TransflowCmd(args []string, controllerURL string) {
    56→	if len(args) == 0 {
    57→		fmt.Println("Usage: ploy transflow run -f <transflow.yaml>")
    58→		return
    59→	}
    60→
    61→	switch args[0] {
    62→	case "run":
    63→		if err := runTransflow(args[1:], controllerURL); err != nil {
    64→			fmt.Fprintf(os.Stderr, "Error: %v\n", err)
    65→			os.Exit(1)
    66→		}
    67→	default:
    68→		fmt.Println("Usage: ploy transflow run -f <transflow.yaml>")
    69→	}
    70→}
