    72→// runTransflow handles the actual transflow execution
    73→func runTransflow(args []string, controllerURL string) error {
    74→	// Parse command line flags
    75→	fs := flag.NewFlagSet("transflow run", flag.ContinueOnError)
    76→	file := fs.String("f", "", "transflow YAML file")
    77→	workDir := fs.String("work-dir", "", "working directory (default: temp dir)")
    78→    dryRun := fs.Bool("dry-run", false, "validate configuration without executing")
    79→    renderPlanner := fs.Bool("render-planner", false, "render planner inputs and HCL (no submission)")
    80→    submitPlanner := fs.Bool("plan", false, "render and (optionally) submit planner job; prints paths. Set TRANSFLOW_SUBMIT=1 to submit.")
    81→    submitReducer := fs.Bool("reduce", false, "render and (optionally) submit reducer job; prints next actions. Set TRANSFLOW_SUBMIT=1 to submit.")
    82→    execFirst := fs.Bool("execute-first", false, "after reading plan.json, print which first option would be executed (sequential stub)")
    83→    execLLM := fs.Bool("exec-llm-first", false, "render and optionally submit llm-exec job for the first plan option of type llm-exec")
    84→    execORW := fs.Bool("exec-orw-first", false, "render and optionally submit orw-apply job for the first plan option of type orw-gen (requires recipe envs)")
    85→    applyFirst := fs.Bool("apply-first", false, "after fetching diff (TRANSFLOW_DIFF_URL/TRANSFLOW_DIFF_PATH), clone repo, validate/apply diff, commit, and run build gate")
    86→	verbose := fs.Bool("v", false, "verbose output")
    87→
    88→	if err := fs.Parse(args); err != nil {
    89→		return fmt.Errorf("flag parsing failed: %w", err)
    90→	}
    91→
    92→	if *file == "" {
    93→		return fmt.Errorf("missing -f <transflow.yaml>")
    94→	}
    95→
    96→	// Load and validate configuration
    97→	config, err := LoadConfig(*file)
    98→	if err != nil {
    99→		return fmt.Errorf("failed to load config from %s: %w", *file, err)
   100→	}
   101→
   102→	if *verbose {
   103→		fmt.Printf("Loaded transflow config: %s\n", config.ID)
   104→	}
   105→
   106→    if *dryRun {
   107→        fmt.Println("Configuration is valid")
   108→        return nil
   109→    }
   110→
   111→	// Create working directory
   112→	var workspaceDir string
   113→	if *workDir != "" {
   114→		workspaceDir = *workDir
   115→		if err := os.MkdirAll(workspaceDir, 0755); err != nil {
   116→			return fmt.Errorf("failed to create work directory %s: %w", workspaceDir, err)
   117→		}
   118→	} else {
   119→		workspaceDir, err = os.MkdirTemp("", "transflow-*")
   120→		if err != nil {
   121→			return fmt.Errorf("failed to create temp directory: %w", err)
   122→		}
   123→		defer os.RemoveAll(workspaceDir)
   124→	}
   125→
   126→	if *verbose {
   127→		fmt.Printf("Using workspace: %s\n", workspaceDir)
   128→	}
   129→
   130→    // Create integrations and runner
   131→    integrations := NewTransflowIntegrations(controllerURL, workspaceDir)
   132→    runner, err := integrations.CreateConfiguredRunner(config)
   133→    if err != nil {
   134→        return fmt.Errorf("failed to create runner: %w", err)
   135→    }
   136→
   137→    if *renderPlanner {
   138→        // Prepare minimal planner inputs/HCL without submitting
   139→        assets, err := runner.RenderPlannerAssets()
   140→        if err != nil {
   141→            return fmt.Errorf("failed to render planner assets: %w", err)
   142→        }
   143→        fmt.Printf("Planner assets rendered:\n  inputs: %s\n  hcl:    %s\n", assets.InputsPath, assets.HCLPath)
   144→        return nil
   145→    }
   146→
   147→    if *submitPlanner {
   148→        assets, err := runner.RenderPlannerAssets()
   149→        if err != nil {
   150→            return fmt.Errorf("failed to render planner assets: %w", err)
   151→        }
   152→        // Substitute placeholders
   153→        hclBytes, err := os.ReadFile(assets.HCLPath)
   154→        if err != nil { return fmt.Errorf("failed to read planner HCL: %w", err) }
   155→        model := os.Getenv("TRANSFLOW_MODEL")
   156→        if model == "" { model = "gpt-4o-mini@2024-08-06" }
   157→        toolsJSON := os.Getenv("TRANSFLOW_TOOLS")
   158→        if toolsJSON == "" { toolsJSON = `{"file":{"allow":["src/**","pom.xml"]},"search":{"provider":"rg","allow":["src/**"]}}` }
   159→        limitsJSON := os.Getenv("TRANSFLOW_LIMITS")
   160→        if limitsJSON == "" { limitsJSON = `{"max_steps":8,"max_tool_calls":12,"timeout":"30m"}` }
   161→        runID := fmt.Sprintf("%s-%d", runner.config.ID, time.Now().Unix())
   162→        rendered := strings.NewReplacer(
   163→            "${MODEL}", model,
   164→            "${TOOLS_JSON}", toolsJSON,
   165→            "${LIMITS_JSON}", limitsJSON,
   166→            "${RUN_ID}", runID,
   167→        ).Replace(string(hclBytes))
   168→        renderedPath := filepath.Join(filepath.Dir(assets.HCLPath), "planner.rendered.hcl")
   169→        if err := os.WriteFile(renderedPath, []byte(rendered), 0644); err != nil {
   170→            return fmt.Errorf("failed to write rendered HCL: %w", err)
   171→        }
   172→        fmt.Printf("Planner HCL rendered: %s\n", renderedPath)
   173→        // Optionally submit if TRANSFLOW_SUBMIT=1
   174→        if os.Getenv("TRANSFLOW_SUBMIT") == "1" {
   175→            timeout := 30 * time.Minute
