   177→                return fmt.Errorf("planner job failed: %w", err)
   178→            }
   179→            // Attempt to read plan.json from URL or locally (also support SeaweedFS filer via bucket/key)
   180→            if url := os.Getenv("TRANSFLOW_PLAN_URL"); url != "" {
   181→                resp, err := http.Get(url)
   182→                if err == nil && resp.StatusCode == 200 {
   183→                    defer resp.Body.Close()
   184→                    b, _ := io.ReadAll(resp.Body)
   185→                    if err := validatePlanJSON(b); err != nil { fmt.Printf("plan.json schema invalid: %v\n", err) } else { printPlanSummary(b) }
   186→                } else {
   187→                    if err != nil { fmt.Printf("Failed to fetch plan URL: %v\n", err) } else { fmt.Printf("Failed to fetch plan URL: %s\n", resp.Status) }
   188→                }
   189→            }
   190→            if filer := os.Getenv("TRANSFLOW_FILER"); filer != "" {
   191→                if bucket := os.Getenv("TRANSFLOW_BUCKET"); bucket != "" {
   192→                    if key := os.Getenv("TRANSFLOW_PLAN_KEY"); key != "" {
   193→                        url := strings.TrimRight(filer, "/") + "/" + strings.TrimLeft(bucket, "/") + "/" + strings.TrimLeft(key, "/")
   194→                        if resp, err := http.Get(url); err == nil && resp.StatusCode == 200 {
   195→                            defer resp.Body.Close()
   196→                            if b, err := io.ReadAll(resp.Body); err == nil { if err := validatePlanJSON(b); err != nil { fmt.Printf("plan.json schema invalid: %v\n", err) } else { printPlanSummary(b) } }
   197→                        }
   198→                    }
   199→                }
   200→            }
   201→            // Attempt to read plan.json locally if provided
   202→            planPath := os.Getenv("TRANSFLOW_PLAN_PATH")
   203→            if planPath == "" {
   204→                // Fallback to workspace/planner/out/plan.json (works if out volume maps locally)
   205→                planPath = filepath.Join(filepath.Dir(renderedPath), "out", "plan.json")
   206→            }
   207→            var planBytes []byte
   208→            if b, err := os.ReadFile(planPath); err == nil {
   209→                planBytes = b
   210→                if err := validatePlanJSON(planBytes); err != nil { fmt.Printf("plan.json schema invalid: %v\n", err) } else { printPlanSummary(planBytes) }
   211→            } else {
   212→                fmt.Println("Planner job completed. Could not read plan.json locally; set TRANSFLOW_PLAN_PATH or TRANSFLOW_PLAN_URL.")
   213→            }
   214→            // Optional reducer artifact print (if provided externally)
   215→            if url := os.Getenv("TRANSFLOW_NEXT_URL"); url != "" {
   216→                resp, err := http.Get(url)
   217→                if err == nil && resp.StatusCode == 200 {
   218→                    defer resp.Body.Close()
   219→                    b, _ := io.ReadAll(resp.Body)
   220→                    if err := validateNextJSON(b); err != nil { fmt.Printf("next.json schema invalid: %v\n", err) } else { printNextSummary(b) }
   221→                }
   222→            }
   223→            if np := os.Getenv("TRANSFLOW_NEXT_PATH"); np != "" {
   224→                if b, err := os.ReadFile(np); err == nil { if err := validateNextJSON(b); err != nil { fmt.Printf("next.json schema invalid: %v\n", err) } else { printNextSummary(b) } }
   225→            }
   226→            if (*execFirst || *execLLM || *execORW || *applyFirst) && len(planBytes) > 0 {
   227→                // Sequential stub: select first option and print intended action
   228→                var parsed struct{ PlanID string `json:"plan_id"`; Options []map[string]any `json:"options"` }
   229→                if err := jsonUnmarshal(planBytes, &parsed); err == nil && len(parsed.Options) > 0 {
   230→                    // Find first matching option for each request
   231→                    var first = parsed.Options[0]
   232→                    id, _ := first["id"].(string)
   233→                    typ, _ := first["type"].(string)
   234→                    if *execFirst {
   235→                        fmt.Printf("Sequential stub: would execute first option %s (%s) next.\n", id, typ)
   236→                        if typ == "llm-exec" {
   237→                            if path, err := runner.RenderLLMExecAssets(id); err == nil { fmt.Printf("Rendered llm_exec HCL: %s\n", path) }
   238→                        }
   239→                    }
   240→                    if *execLLM {
   241→                        // Find first llm-exec
   242→                        for _, o := range parsed.Options {
   243→                            if t, _ := o["type"].(string); t == "llm-exec" {
   244→                                lid, _ := o["id"].(string)
   245→                                if hcl, err := runner.RenderLLMExecAssets(lid); err == nil {
   246→                                    fmt.Printf("Rendered llm_exec HCL: %s\n", hcl)
   247→                                    // Substitute envs
   248→                                    hb, _ := os.ReadFile(hcl)
   249→                                    model := os.Getenv("TRANSFLOW_MODEL"); if model == "" { model = "gpt-4o-mini@2024-08-06" }
   250→                                    tools := os.Getenv("TRANSFLOW_TOOLS"); if tools == "" { tools = `{"file":{"allow":["src/**","pom.xml"]}}` }
   251→                                    limits := os.Getenv("TRANSFLOW_LIMITS"); if limits == "" { limits = `{"max_steps":8,"max_tool_calls":12,"timeout":"30m"}` }
   252→                                    runID := fmt.Sprintf("%s-%d", runner.config.ID, time.Now().Unix())
   253→                                    rendered := strings.NewReplacer(
   254→                                        "${MODEL}", model,
   255→                                        "${TOOLS_JSON}", tools,
   256→                                        "${LIMITS_JSON}", limits,
   257→                                        "${RUN_ID}", runID,
   258→                                    ).Replace(string(hb))
   259→                                    renderedPath := strings.ReplaceAll(hcl, ".rendered.hcl", ".rendered.submitted.hcl")
   260→                                    _ = os.WriteFile(renderedPath, []byte(rendered), 0644)
   261→                                    fmt.Printf("Rendered llm_exec HCL (substituted): %s\n", renderedPath)
   262→                                    if os.Getenv("TRANSFLOW_SUBMIT") == "1" {
   263→                                        if err := orchestration.SubmitAndWaitTerminal(renderedPath, 30*time.Minute); err != nil {
   264→                                            fmt.Printf("llm-exec job failed: %v\n", err)
   265→                                        } else {
