   267→                                            diffPath := filepath.Join(filepath.Dir(renderedPath), "out", "diff.patch")
   268→                                            fmt.Printf("llm-exec completed. diff.patch expected at: %s (or via TRANSFLOW_DIFF_URL/TRANSFLOW_DIFF_PATH).\n", diffPath)
   269→                                        }
   270→                                    } else {
   271→                                        fmt.Println("Skipping llm-exec submission (unset TRANSFLOW_SUBMIT).")
   272→                                    }
   273→                                }
   274→                                break
   275→                            }
   276→                        }
   277→                    }
   278→                    if *execORW {
   279→                        // Find first orw-gen
   280→                        for _, o := range parsed.Options {
   281→                            if t, _ := o["type"].(string); t == "orw-gen" {
   282→                                oid, _ := o["id"].(string)
   283→                                if hcl, err := runner.RenderORWApplyAssets(oid); err == nil {
   284→                                    fmt.Printf("Rendered orw_apply HCL: %s\n", hcl)
   285→                                    hb, _ := os.ReadFile(hcl)
   286→                                    // Recipe envs required: TRANSFLOW_RECIPE_CLASS / TRANSFLOW_RECIPE_COORDS
   287→                                    rclass := os.Getenv("TRANSFLOW_RECIPE_CLASS"); if rclass == "" { rclass = "org.openrewrite.java.migrate.Java11toJava17" }
   288→                                    rcoords := os.Getenv("TRANSFLOW_RECIPE_COORDS")
   289→                                    rtimeout := os.Getenv("TRANSFLOW_RECIPE_TIMEOUT"); if rtimeout == "" { rtimeout = "10m" }
   290→                                    rendered := strings.NewReplacer(
   291→                                        "${RECIPE_CLASS}", rclass,
   292→                                        "${RECIPE_COORDS}", rcoords,
   293→                                        "${RECIPE_TIMEOUT}", rtimeout,
   294→                                    ).Replace(string(hb))
   295→                                    renderedPath := strings.ReplaceAll(hcl, ".rendered.hcl", ".rendered.submitted.hcl")
   296→                                    _ = os.WriteFile(renderedPath, []byte(rendered), 0644)
   297→                                    fmt.Printf("Rendered orw_apply HCL (substituted): %s\n", renderedPath)
   298→                                    if os.Getenv("TRANSFLOW_SUBMIT") == "1" {
   299→                                        if err := orchestration.SubmitAndWaitTerminal(renderedPath, 30*time.Minute); err != nil {
   300→                                            fmt.Printf("orw-apply job failed: %v\n", err)
   301→                                        } else {
   302→                                            diffPath := filepath.Join(filepath.Dir(renderedPath), "out", "diff.patch")
   303→                                            fmt.Printf("orw-apply completed. diff.patch expected at: %s\n", diffPath)
   304→                                        }
   305→                                    } else {
   306→                                        fmt.Println("Skipping orw-apply submission (unset TRANSFLOW_SUBMIT).")
   307→                                    }
   308→                                }
   309→                                break
   310→                            }
   311→                        }
   312→                    }
   313→                    if *applyFirst {
   314→                        // Fetch diff content path or URL
   315→                        var diffPath string
   316→                        if url := os.Getenv("TRANSFLOW_DIFF_URL"); url != "" {
   317→                            if resp, err := http.Get(url); err == nil && resp.StatusCode == 200 {
   318→                                b, _ := io.ReadAll(resp.Body); _ = resp.Body.Close()
   319→                                // Write to temp file in workspace
   320→                                dp := filepath.Join(runner.workspaceDir, "apply", "diff.patch")
   321→                                _ = os.MkdirAll(filepath.Dir(dp), 0755)
   322→                                _ = os.WriteFile(dp, b, 0644)
