   328→                        }
   329→                        if diffPath == "" {
   330→                            fmt.Println("Missing TRANSFLOW_DIFF_URL or TRANSFLOW_DIFF_PATH for --apply-first")
   331→                        } else {
   332→                            // Prepare repo and apply diff
   333→                            repoPath, _, err := runner.PrepareRepo(context.Background())
   334→                            if err != nil { fmt.Printf("PrepareRepo failed: %v\n", err) } else {
   335→                                if err := runner.ApplyDiffAndBuild(context.Background(), repoPath, diffPath); err != nil {
   336→                                    fmt.Printf("Apply/build failed: %v\n", err)
   337→                                } else {
   338→                                    fmt.Println("Apply/build succeeded")
   339→                                }
   340→                            }
   341→                        }
   342→                    }
   343→                }
   344→            }
   345→        } else {
   346→            fmt.Println("Skipping submission (unset TRANSFLOW_SUBMIT).")
   347→        }
   348→        return nil
   349→    }
