   355→        }
   356→        // Substitute placeholders
   357→        hclBytes, err := os.ReadFile(assets.HCLPath)
   358→        if err != nil { return fmt.Errorf("failed to read reducer HCL: %w", err) }
   359→        model := os.Getenv("TRANSFLOW_MODEL")
   360→        if model == "" { model = "gpt-4o-mini@2024-08-06" }
   361→        toolsJSON := os.Getenv("TRANSFLOW_TOOLS")
   362→        if toolsJSON == "" { toolsJSON = `{"file":{"allow":["src/**","pom.xml"]}}` }
   363→        limitsJSON := os.Getenv("TRANSFLOW_LIMITS")
   364→        if limitsJSON == "" { limitsJSON = `{"max_steps":4,"max_tool_calls":8,"timeout":"15m"}` }
   365→        runID := fmt.Sprintf("%s-%d", runner.config.ID, time.Now().Unix())
   366→        rendered := strings.NewReplacer(
   367→            "${MODEL}", model,
   368→            "${TOOLS_JSON}", toolsJSON,
   369→            "${LIMITS_JSON}", limitsJSON,
   370→            "${RUN_ID}", runID,
   371→        ).Replace(string(hclBytes))
   372→        renderedPath := filepath.Join(filepath.Dir(assets.HCLPath), "reducer.rendered.hcl")
   373→        if err := os.WriteFile(renderedPath, []byte(rendered), 0644); err != nil {
   374→            return fmt.Errorf("failed to write rendered HCL: %w", err)
   375→        }
   376→        fmt.Printf("Reducer HCL rendered: %s\n", renderedPath)
   377→        if os.Getenv("TRANSFLOW_SUBMIT") == "1" {
   378→            timeout := 15 * time.Minute
   379→            if err := orchestration.SubmitAndWaitTerminal(renderedPath, timeout); err != nil {
   380→                return fmt.Errorf("reducer job failed: %w", err)
   381→            }
   382→            // Fetch next.json via URL or local path
   383→            if url := os.Getenv("TRANSFLOW_NEXT_URL"); url != "" {
   384→                resp, err := http.Get(url)
   385→                if err == nil && resp.StatusCode == 200 {
   386→                    defer resp.Body.Close()
   387→                    b, _ := io.ReadAll(resp.Body)
   388→                    printNextSummary(b)
   389→                } else if err != nil {
   390→                    fmt.Printf("Failed to fetch next URL: %v\n", err)
   391→                }
   392→            }
   393→            np := os.Getenv("TRANSFLOW_NEXT_PATH")
   394→            if np == "" { np = filepath.Join(filepath.Dir(renderedPath), "out", "next.json") }
   395→            if b, err := os.ReadFile(np); err == nil { printNextSummary(b) } else { fmt.Println("Reducer job completed. Could not read next.json; set TRANSFLOW_NEXT_PATH or TRANSFLOW_NEXT_URL.") }
   396→        } else {
   397→            fmt.Println("Skipping reducer submission (unset TRANSFLOW_SUBMIT).")
   398→        }
   399→        return nil
   400→    }
